import { useState } from "react";
import { motion } from "framer-motion";

/* ===============================
   🎨 DESIGN VARIABLES
================================= */

const design = {
  colors: {
    background: "bg-gradient-to-br from-slate-950 via-slate-900 to-slate-800",
    card: "bg-white/10 backdrop-blur-xl",
    title: "text-white",
    subtitle: "text-gray-400",
    inputBg: "bg-white/5",
    inputBorder: "border-white/20",
    inputText: "text-white",
    button: "bg-indigo-600",
    buttonHover: "hover:bg-indigo-700",
  },
  layout: {
    container: "min-h-screen flex items-center justify-center px-4",
    card: "w-full max-w-md rounded-2xl p-8 shadow-2xl border border-white/10",
    input: "w-full p-3 rounded-lg border outline-none transition duration-300",
    button:
      "w-full py-3 rounded-lg font-semibold transition duration-300",
  },
  animation: {
    container: {
      initial: { opacity: 0 },
      animate: { opacity: 1 },
      transition: { duration: 0.6 },
    },
    card: {
      initial: { y: 40, opacity: 0 },
      animate: { y: 0, opacity: 1 },
      transition: { duration: 0.6, delay: 0.2 },
    },
  },
};

/* ===============================
   🚀 COMPONENT
================================= */

const AdminLogin = () => {
  const [form, setForm] = useState({
    email: "",
    password: "",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Form Data:", form);
  };

  return (
    <motion.div
      {...design.animation.container}
      className={`${design.colors.background} ${design.layout.container}`}
    >
      <motion.div
        {...design.animation.card}
        className={`${design.colors.card} ${design.layout.card}`}
      >
        {/* Title */}
        <div className="text-center mb-8">
          <h2 className={`text-3xl font-bold ${design.colors.title}`}>
            Admin Login
          </h2>
          <p className={`text-sm mt-2 ${design.colors.subtitle}`}>
            Enter your credentials to access dashboard
          </p>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="space-y-5">
          <input
            type="email"
            name="email"
            placeholder="Admin Email"
            value={form.email}
            onChange={handleChange}
            className={`${design.layout.input} ${design.colors.inputBg} ${design.colors.inputBorder} ${design.colors.inputText}`}
          />

          <input
            type="password"
            name="password"
            placeholder="Password"
            value={form.password}
            onChange={handleChange}
            className={`${design.layout.input} ${design.colors.inputBg} ${design.colors.inputBorder} ${design.colors.inputText}`}
          />

          <button
            type="submit"
            className={`${design.layout.button} ${design.colors.button} ${design.colors.buttonHover} text-white`}
          >
            Sign In
          </button>
        </form>
      </motion.div>
    </motion.div>
  );
};

export default AdminLogin;
